def gen(rng, size):
    k = max(1, min(26, size))
    letters = [chr(ord('a') + i) for i in range(k)]
    chars = letters * 2
    rng.shuffle(chars)
    s = ''.join(chars)
    distance = [0] * 26
    first = {}
    for idx, ch in enumerate(s):
        if ch in first:
            distance[ord(ch) - 97] = idx - first[ch] - 1
        else:
            first[ch] = idx
    return [s, distance]

