var checkDistances = function(s, distance) {
    const first = {};
    for (let idx = 0; idx < s.length; idx++) {
        const ch = s[idx];
        const k = ch.charCodeAt(0) - 97;
        if (first[ch] !== undefined) {
            if (idx - first[ch] - 1 !== distance[k]) return false;
        } else {
            first[ch] = idx;
        }
    }
    return true;
